import { useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import { useLocation, Navigate } from "react-router-dom";

export default function RequireAuth({ children, allowedRoles = [] }) {
  const { isLoggedIn, openLogin, user } = useAuth();
  const location = useLocation();
  const hasRoleAccess = allowedRoles.length === 0 || allowedRoles.includes(user?.role);

  useEffect(() => {
    if (!isLoggedIn) openLogin();
  }, [isLoggedIn, openLogin]);

  if (isLoggedIn && hasRoleAccess) return children;

  if (isLoggedIn && !hasRoleAccess) {
    return <Navigate to={user?.role === "ADMIN" ? "/admin" : "/menu"} replace />;
  }

  // redirect to menu preview when not logged in
  return <Navigate to="/menu" state={{ from: location }} replace />;
}
